parameters.jsCode:
// Set tenant context variable for all downstream nodes
// This is the RLS boundary — all DB queries after this use this tenant_id
const tenant = $('DB: Lookup Tenant + System Prompt').first().json;

if (!tenant || !tenant.id) {
  throw new Error(`Tenant not found: ${$json.tenantId}`);
}

// Set RLS context
$vars.set('current_tenant_id', tenant.id);
$vars.set('tenant_billing_status', tenant.billing_status);
$vars.set('tenant_conv_used', tenant.conv_used_this_cycle);
$vars.set('tenant_conv_limit', tenant.conv_limit_this_cycle);
$vars.set('system_prompt', tenant.system_prompt);

return [{
  json: {
    tenantId: tenant.id,
    billingStatus: tenant.billing_status,
    convUsed: tenant.conv_used_this_cycle,
    convLimit: tenant.conv_limit_this_cycle,
    systemPrompt: tenant.system_prompt,
    customerPhone: $('Webhook: SMS Inbound').first().json.customerPhone,
    messageBody: $('Webhook: SMS Inbound').first().json.body,
    messageSid: $('Webhook: SMS Inbound').first().json.messageSid,
    atSoftLimit: $('Webhook: SMS Inbound').first().json.atSoftLimit ?? false,
    triggerType: $('Webhook: SMS Inbound').first().json.triggerType ?? 'sms_reply',
  }
}];

parameters.query:
SET LOCAL app.current_tenant_id = '{{ $vars.current_tenant_id }}';
SELECT * FROM get_or_create_conversation(
  '{{ $json.tenantId }}'::uuid,
  '{{ $json.customerPhone }}'
);

